# Open all output windows
for w in ops('/project1/window*'):
    w.par.winopen.pulse()

# Close all output windows
for w in ops('/project1/window*'):
    w.par.winclose.pulse()

# Toggle a specific window
win = op('/project1/window1')
if win.isOpen:
    win.par.winclose.pulse()
else:
    win.par.winopen.pulse()
